if (! function_exists('webhook_listener')) {
    function webhook_listener($action, $port = null, $pid = null, $db_name = null, $max_payloads = null)
    {
        // Webhook Listener — first inbound receiver
        $action = $action ?? '';
        $port = $port ?? 8765;
        $pid = $pid ?? 0;
        $db_name = $db_name ?? 'webhooks.sqlite';
        $max_payloads = $max_payloads ?? 50;

        $allowed = ['start','stop','payloads','status'];
        if (!in_array($action, $allowed)) {
            return ['error' => 'Unknown action. Use: ' . implode(', ', $allowed), 'success' => false];
        }
        $port = max(8000, min(9999, (int)$port));
        $max_payloads = max(1, min(200, (int)$max_payloads));

        $W = __DIR__ . '/../workspace';
        $db_path = $W . '/' . basename($db_name);
        $router_path = $W . '/webhook_router.php';
        $pid_file = $W . '/webhook_listener.pid';
        $log_path = $W . '/webhook_server.log';

        // Build PHP open tag: 60=<, 63=?, 112=p, 104=h, 112=p
        $O = sprintf('%c%c%c%c%c', 60, 63, 112, 104, 112);

        if ($action === 'start') {
            // Check for existing server
            if (file_exists($pid_file)) {
                $old_pid = (int)trim(file_get_contents($pid_file));
                $running = false;
                if (PHP_OS_FAMILY === 'Windows') {
                    $c = @shell_exec("tasklist /FI \"PID eq $old_pid\" 2>NUL");
                    $running = $c !== null && strpos($c, (string)$old_pid) !== false;
                } else {
                    $c = @shell_exec("kill -0 $old_pid 2>/dev/null && echo alive");
                    $running = trim($c ?? '') === 'alive';
                }
                if ($running) {
                    return ['error' => "Server already running on PID $old_pid", 'pid' => $old_pid, 'success' => false];
                }
                @unlink($pid_file);
            }

            // Write router file
            $router_body = $O . "\n"
                . '$m = $_SERVER["REQUEST_METHOD"] ?? "UNKNOWN";' . "\n"
                . '$h = [];' . "\n"
                . 'foreach($_SERVER as $k=>$v){if(strpos($k,"HTTP_")===0){$h[str_replace("_","-",strtolower(substr($k,5)))]=$v;}}' . "\n"
                . '$b = file_get_contents("php://input");' . "\n"
                . '$db = __DIR__ . "/' . basename($db_name) . '";' . "\n"
