                . 'echo json_encode(["ok"=>true,"t"=>$ts]);return true;' . "\n";

            file_put_contents($router_path, $router_body);

            // Init database
            try {
                $pdo = new PDO("sqlite:$db_path");
                $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $pdo->exec("CREATE TABLE IF NOT EXISTS wh (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    ts TEXT, m TEXT, p TEXT, ip TEXT,
                    hdrs TEXT, body TEXT
                )");
            } catch (Exception $e) {
                return ['error' => 'DB init: ' . $e->getMessage(), 'success' => false];
            }

            // Start server
            $pid_val = 0;
            if (PHP_OS_FAMILY === 'Windows') {
                $cmd = sprintf('php -S 0.0.0.0:%d "%s"', $port, $router_path);
                $d = [0 => ['pipe','r'], 1 => ['file',$log_path,'a'], 2 => ['file',$log_path,'a']];
                $proc = @proc_open($cmd, $d, $pipes, $W);
                if (is_resource($proc)) {
                    $st = proc_get_status($proc);
