                    if (isset($pipes[0])) fclose($pipes[0]);
                }
            } else {
                $cmd = sprintf('nohup php -S 0.0.0.0:%d "%s" > "%s" 2>&1 & echo $!', $port, $router_path, $log_path);
                $pid_val = (int)trim((string)@shell_exec($cmd));
            }

            if ($pid_val <= 0) {
                $log = file_exists($log_path) ? file_get_contents($log_path) : '';
                return ['error' => 'Failed to start server', 'log' => $log, 'success' => false];
            }

            file_put_contents($pid_file, (string)$pid_val);
            usleep(300000);

            $alive = false;
            if (PHP_OS_FAMILY !== 'Windows') {
                $c = @shell_exec("kill -0 $pid_val 2>/dev/null && echo alive");
                $alive = trim($c ?? '') === 'alive';
            } else {
                $alive = $pid_val > 0;
            }

            return [
                'success' => true,
                'action' => 'started',
                'port' => $port,
                'pid' => $pid_val,
                'running' => $alive,
                'database' => $db_name,
                'test_cmd' => "curl -X POST http://localhost:$port/hooks/test -H 'Content-Type: application/json' -d '{\"event\":\"ping\"}'",
                'stop_cmd' => "webhook_listener action=stop pid=$pid_val",
