            if (PHP_OS_FAMILY === 'Windows') @shell_exec("taskkill /F /PID $pid 2>NUL");
            else @shell_exec("kill $pid 2>/dev/null");
            if (file_exists($pid_file)) @unlink($pid_file);
            return ['success' => true, 'action' => 'stopped', 'pid' => $pid];
