            }
            $cnt = 0;
            try {
                if (file_exists($db_path)) {
                    $r = (new PDO("sqlite:$db_path"))->query("SELECT COUNT(*) as c FROM wh");
                    $cnt = (int)$r->fetch(PDO::FETCH_ASSOC)['c'];
